def max_bias(pob, counts):
    n = sum(counts.values())
    return max(abs(counts[k] / n - pob[k]) for k in pob)
print(round(max_bias({"Lima": 0.5, "Cusco": 0.5}, {"Lima": 9, "Cusco": 1}), 2))

